    ssh_dir = os.path.join(home, '.ssh')

    if not os.path.exists(ssh_dir):
        return []

    keys = []
    common_names = ['id_rsa', 'id_dsa', 'id_ecdsa', 'id_ed25519', 'id_rsa_cloud', 'id_ed25519_prod']

    for name in common_names:
        key_path = os.path.join(ssh_dir, name)
        if os.path.exists(key_path):
            keys.append({
                'path': key_path,
                'name': name,
                'size': os.path.getsize(key_path)
            })

    for entry in os.listdir(ssh_dir):
        entry_path = os.path.join(ssh_dir, entry)
        if os.path.isfile(entry_path) and not entry.endswith('.pub') and entry not in common_names:
            try:
                with open(entry_path, 'rb') as f:
                    header = f.read(64)
                    if b'PRIVATE KEY' in header or OPENSSH_MAGIC in header:
                        keys.append({
                            'path': entry_path,
                            'name': entry,
                            'size': os.path.getsize(entry_path)
                        })
            except:
                pass

    return keys

def parse_openssh_new_format(key_data):
    if not key_data.startswith(OPENSSH_MAGIC):
        return None

    offset = len(OPENSSH_MAGIC)

    def read_string():
        nonlocal offset
        if offset + 4 > len(key_data):
            return None
        length = struct.unpack('>I', key_data[offset:offset+4])[0]
        offset += 4
        if offset + length > len(key_data):
            return None
        data = key_data[offset:offset+length]
        offset += length
        return data

    cipher = read_string()
    if cipher is None:
        return None

    kdf = read_string()
    if kdf is None:
        return None

    kdf_options = read_string()
    if kdf_options is None:
        return None

    num_keys_data = key_data[offset:offset+4]
    if len(num_keys_data) < 4:
        return None
    num_keys = struct.unpack('>I', num_keys_data)[0]
    offset += 4

    public_key = read_string()
    if public_key is None:
        return None

    encrypted_blob = read_string()
    if encrypted_blob is None:
        return None

    result = {
        'magic': OPENSSH_MAGIC.decode('utf-8', errors='ignore').strip('\x00'),
        'cipher': cipher.decode('utf-8', errors='ignore'),
        'kdf': kdf.decode('utf-8', errors='ignore'),
        'kdf_options_len': len(kdf_options),
        'num_keys': num_keys,
        'public_key_len': len(public_key),
        'encrypted_blob_len': len(encrypted_blob)
    }

    if cipher == b'none':
        result['encrypted'] = False
    else:
        result['encrypted'] = True

    if kdf == b'bcrypt':
        if len(kdf_options) >= 8:
            salt_len = struct.unpack('>I', kdf_options[0:4])[0]
            result['bcrypt_salt_len'] = salt_len
            if len(kdf_options) >= 8 + salt_len:
                rounds = struct.unpack('>I', kdf_options[4+salt_len:8+salt_len])[0]
                result['bcrypt_rounds'] = rounds

    return result

def parse_legacy_pem(key_data):
    if b'-----BEGIN' not in key_data:
        return None

    lines = key_data.decode('utf-8', errors='ignore').split('\n')

    key_type = None
    encrypted = False
    dek_info = None

    for line in lines:
        if 'BEGIN' in line:
            if 'RSA PRIVATE KEY' in line:
                key_type = 'RSA'
            elif 'DSA PRIVATE KEY' in line:
                key_type = 'DSA'
            elif 'EC PRIVATE KEY' in line:
                key_type = 'EC'
            elif 'PRIVATE KEY' in line:
                key_type = 'PKCS8'

        if 'Proc-Type' in line and 'ENCRYPTED' in line:
            encrypted = True

        if 'DEK-Info' in line:
            dek_info = line.split(':', 1)[1].strip() if ':' in line else None

    b64_data = []
    in_body = False
    for line in lines:
        if 'BEGIN' in line:
            in_body = True
            continue
        if 'END' in line:
            break
        if in_body and not line.startswith('Proc-Type') and not line.startswith('DEK-Info'):
            b64_data.append(line.strip())

    encoded_size = sum(len(l) for l in b64_data)

    return {
        'format': 'PEM',
        'key_type': key_type,
        'encrypted': encrypted,
        'dek_info': dek_info,
        'encoded_size': encoded_size
    }

def parse_known_hosts(ssh_dir=None):
